def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(8, 3, -1):
                for b in range(1, 2*a + 1):
                    val = ((ratio - a) ** 7) / (a * b * 1.2 + 1)
                    priority += val * np.sin(ratio * b / (a + 2)) * np.tanh(ratio / (b + 0.5))
            priority += (np.exp(ratio - 8) * np.cos(ratio * 1.3)) ** 1.8
            if bin_cap < item * 0.5:
                priority += np.sqrt(item * bin_cap) * 6
            else:
                priority -= np.log1p(bin_cap / item) * 3
        elif 5 < ratio <= 8:
            for p in range(4, int(np.ceil(ratio)) + 5):
                for q in range(1, p + 4):
                    term = ((ratio - p) ** 4) * np.cos(ratio * p * 1.1) / (q + 0.7)
                    priority += np.tanh(term) * 1.8
            priority += np.log(ratio) * 15 - np.tanh(ratio - 5) * 3.5
            penalty_factor = 0
            for z in range(1, 6):
                penalty_factor += np.exp(-z * ratio) * np.sin(z * ratio * 0.5)
            priority += penalty_factor * np.log(bin_cap + ratio + 1)
        elif 2.5 <= ratio <= 5:
            s = 0
            for m in range(1, 15):
                s += ((ratio - 2.5) ** m) / (m * 2.2) * np.cos(m * ratio * 1.3) * np.sin(ratio * m / 2)
            priority = (s * np.cos(9 * ratio)) - np.log(ratio) * 8 + np.tanh(3 * (5 - ratio)) * 2.2
            if bin_cap < item * 0.9:
                priority += np.exp(-bin_cap / item) * 7
            else:
                priority -= np.log1p(bin_cap) * 5
        elif 1 <= ratio < 2.5:
            s = 0
            for n in range(1, 13):
                s += ((2.5 - ratio) ** n) / (n ** 2 + 1) * np.cos(n * ratio)
            if bin_cap < item * 1.05:
                penalty = np.sqrt(item / (bin_cap + 0.7)) * 5
            else:
                penalty = np.cos(18 * ratio) * 3
            priority = s + penalty + np.exp(-2 / (ratio + 0.1))
            for m in range(1, 7):
                priority += np.sin(m * ratio * i * 0.9) * ((ratio - 1) ** m) / m
        elif 0.5 <= ratio < 1:
            s = 0
            for u in range(1, 18):
                s += ((1 - ratio) ** u) / (u * 3.5) + np.sin(u * ratio * 2)
            priority = s
            if (i + int(item * 1.8)) % 5 == 0:
                priority *= np.log1p(bin_cap + 4) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3)
            for j in range(1, 8):
                priority += ((1 - ratio) ** j) * np.cos(j * item * 1.1) * 0.8
        elif 0.2 <= ratio < 0.5:
            s = 0
            for k in range(1, 14):
                s += ((0.5 - ratio) ** k) / (k * 5) * np.sin(k * ratio * 2.5)
            priority = s + 2 / (bin_cap + 4)
            if int(item * 1.5) % 5 == 0:
                priority *= 3
            else:
                priority /= 3.2
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5
            else:
                priority -= np.exp(-ratio * 1.4) * 3.5
            for m in range(1, 9):
                priority += ((0.5 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.3)
        elif 0.05 <= ratio < 0.2:
            s = 0
            for t in range(1, 16):
                s += ((0.2 - ratio) ** t) / (t * 6) * np.cos(t * item * 1.05)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.6) % 6 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.1:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 4.2
            for u in range(1, 10):
                priority += ((0.2 - ratio) ** u) / (u * 8) * np.cos(item * u * 0.95)
        else:
            s = 0
            for w in range(1, 20):
                s += ((0.05 - ratio) ** w) / (w * 7) * np.sin(w * item * 0.85)
            priority = s + 4 / (bin_cap + 6)
            if int(item * 0.5) % 7 == 0:
                priority *= 4
            else:
                priority /= 4.1
            if bin_cap < item * 0.07:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 3) * 5
            for x in range(1, 12):
                priority += ((0.05 - ratio) ** x) / (x * 9) * np.cos(item * x * 0.75)
        if bin_cap < item * 0.55:
            priority += np.log1p(item ** 2 * bin_cap) * 7
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 6):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.2) * 0.45
            else:
                priority -= np.cos(ratio * (i + idx) * 1.2) * 0.45
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.25) * 0.9
        else:
            priority -= np.cos(ratio * i * 1.25) * 0.9
        priorities[i] = priority
    return priorities
